     1→import React, { useMemo } from "react";
     2→
     3→// ─── Inline parsing ───────────────────────────────────────────────────────────
     4→
     5→type InlineNode =
     6→  | { t: "text"; s: string }
     7→  | { t: "bold"; s: string }
     8→  | { t: "italic"; s: string }
     9→  | { t: "code"; s: string };
    10→
    11→function parseInline(raw: string): InlineNode[] {
    12→  const nodes: InlineNode[] = [];
    13→  const re = /(\*\*(?:[^*]|\*(?!\*))+?\*\*|\*(?:[^*\n])+?\*|``(?:[^`]|`(?!`))+``|`[^`\n]+?`)/g;
    14→  let last = 0;
    15→  let m: RegExpExecArray | null;
    16→  while ((m = re.exec(raw)) !== null) {
    17→    if (m.index > last) nodes.push({ t: "text", s: raw.slice(last, m.index) });
    18→    const tok = m[1];
    19→    if (tok.startsWith("**")) nodes.push({ t: "bold", s: tok.slice(2, -2) });
    20→    else if (tok.startsWith("``")) nodes.push({ t: "code", s: tok.slice(2, -2).trim() });
    21→    else if (tok.startsWith("`")) nodes.push({ t: "code", s: tok.slice(1, -1) });
    22→    else nodes.push({ t: "italic", s: tok.slice(1, -1) });
    23→    last = m.index + tok.length;
    24→  }
    25→  if (last < raw.length) nodes.push({ t: "text", s: raw.slice(last) });
    26→  return nodes;
    27→}
    28→
    29→// ─── Block parsing ────────────────────────────────────────────────────────────
    30→
    31→type Block =
    32→  | { kind: "code"; lang: string; code: string }
    33→  | { kind: "h"; level: 1 | 2 | 3; inline: InlineNode[] }
    34→  | { kind: "bullets"; items: InlineNode[][] }
    35→  | { kind: "numbered"; items: InlineNode[][] }
    36→  | { kind: "hr" }
    37→  | { kind: "table"; headers: InlineNode[][]; rows: InlineNode[][][] }
    38→  | { kind: "para"; inline: InlineNode[] };
    39→
    40→function parseBlocks(md: string): Block[] {
    41→  const lines = md.split("\n");
    42→  const out: Block[] = [];
    43→  let i = 0;
    44→  while (i < lines.length) {
    45→    const line = lines[i];
    46→    const trimmed = line.trimStart();
    47→    if (trimmed.startsWith("```") || trimmed.startsWith("~~~")) {
    48→      const fence = trimmed.slice(0, 3);
    49→      const lang = trimmed.slice(3).trim();
