              gap={6}
              mb={4}
              style={{ cursor: "pointer" }}
              onClick={() => setToolsExpanded((v) => !v)}
            >
              <Text size="xs" c="dimmed">
                {totalTools} tool {totalTools === 1 ? "use" : "uses"}
              </Text>
              <Text size="xs" c="dimmed">{toolsExpanded ? "▲" : "▼"}</Text>
            </Group>
            <Collapse in={toolsExpanded}>
