    50→  branch: string | null;
    51→  intent: string | null;
    52→  /** true when this session is currently indexed in a shadow branch */
    53→  isLive: boolean;
    54→}
    55→
    56→interface OverviewResponse {
    57→  sessionId: string;
    58→  summary: string;
    59→  keywords: string[];
    60→  startedAt: string;
    61→  endedAt: string;
    62→}
