   362→  app.get("/api/v2/checkpoints", async (_req, res) => {
   363→    try {
   364→      const checkpoints = await db.checkpointMetadata.findMany({
   365→        include: {
   366→          tokenUsage: true,
   367→          filesTouched: { include: { filePath: true } },
   368→        },
   369→      });
   370→
   371→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   372→
   373→      const sessions = await db.checkpointSessionMetadata.findMany({
   374→        where:   { checkpointId: { in: checkpointIds } },
   375→        orderBy: V2_SESSION_ORDER,
   376→        include: V2_SESSION_INCLUDE,
   377→      });
   378→
   379→      // Group sessions by checkpointId
   380→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   381→      for (const s of sessions) {
   382→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   383→        arr.push(s);
   384→        sessionsByCheckpoint.set(s.checkpointId, arr);
   385→      }
   386→
   387→      res.json(checkpoints.map((c) => {
   388→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   389→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   390→        const latestCreatedAt = cpSessions
   391→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   392→          .map((s) => s.createdAt)
   393→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   394→        return {
   395→          id:               c.id,
   396→          checkpointId:     c.checkpointId,
   397→          cliVersion:       c.cliVersion,
   398→          strategy:         c.strategy,
   399→          branch:           c.branch,
   400→          checkpointsCount: c.checkpointsCount,
   401→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   402→          tokenUsage: c.tokenUsage ? {
   403→            inputTokens:         c.tokenUsage.inputTokens,
   404→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   405→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   406→            outputTokens:        c.tokenUsage.outputTokens,
   407→            apiCallCount:        c.tokenUsage.apiCallCount,
   408→          } : null,
   409→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   410→          sessionCount:  cpSessions.length,
   411→          summary: summary ? mapV2Summary(summary) : null,
   412→        };
   413→      }));
   414→    } catch (err) {
   415→      res.status(500).json({ error: String(err) });
