    68→// A single line from full.jsonl — fields vary by type
    69→export interface FullJsonlEvent {
    70→  uuid?: string;
    71→  messageId?: string;      // used by "file-history-snapshot" instead of uuid
    72→  sessionId?: string;
    73→  parentUuid?: string;
    74→  type: string;
    75→  timestamp?: string;
    76→  cwd?: string;
    77→  gitBranch?: string;
    78→  slug?: string;
    79→  version?: string;
    80→  planContent?: string;
    81→  toolUseID?: string;
    82→  parentToolUseID?: string;
    83→  isSidechain?: boolean;
    84→  userType?: string;
    85→  message?: unknown;
    86→  data?: unknown;
    87→  [key: string]: unknown;
    88→}
    89→
    90→// ─── Parsing ──────────────────────────────────────────────────────────────────
    91→
    92→/**
    93→ * Parse a full.jsonl string into an array of event objects.
    94→ * Malformed lines are silently skipped.
    95→ */
    96→export function parseFullJsonl(content: string): FullJsonlEvent[] {
    97→  const out: FullJsonlEvent[] = [];
    98→  for (const line of content.split("\n")) {
    99→    const trimmed = line.trim();
   100→    if (!trimmed) continue;
   101→    try {
   102→      out.push(JSON.parse(trimmed) as FullJsonlEvent);
   103→    } catch {
   104→      // skip malformed line
   105→    }
   106→  }
   107→  return out;
   108→}
   109→
   110→/** Return the unique key for an event, preferring uuid then messageId. */
   111→function eventKey(e: FullJsonlEvent): string | null {
   112→  return e.uuid ?? e.messageId ?? null;
   113→}
