   288→export function subscribeToUpdates(onUpdate: () => void): () => void {
   289→  let ws: WebSocket | null = null;
   290→  let timer: ReturnType<typeof setTimeout> | null = null;
   291→  let closed = false;
   292→  let delay = 1000;
   293→
   294→  function connect() {
   295→    if (closed) return;
   296→    ws = new WebSocket(WS_URL);
   297→
   298→    ws.onopen = () => {
   299→      delay = 1000; // reset backoff on successful connection
   300→    };
   301→
   302→    ws.onmessage = (e) => {
   303→      try {
   304→        const msg = JSON.parse(e.data as string) as { type: string };
   305→        if (msg.type === "sessions_updated") onUpdate();
   306→      } catch {
   307→        // ignore malformed messages
   308→      }
   309→    };
   310→
   311→    ws.onclose = () => {
   312→      if (closed) return;
   313→      timer = setTimeout(() => {
   314→        delay = Math.min(delay * 2, 30000);
   315→        connect();
   316→      }, delay);
   317→    };
   318→
   319→    ws.onerror = () => {
   320→      ws?.close();
   321→    };
   322→  }
   323→
   324→  connect();
   325→
   326→  return () => {
   327→    closed = true;
   328→    if (timer !== null) clearTimeout(timer);
   329→    ws?.close();
   330→  };
   331→}
