   197→function logEventsToEvents(logEvents: LogEventItem[]): Event[] {
   198→  const result: Event[] = [];
   199→  let id = -1;
   200→  let lastAssistantText: string | null = null;
   201→  let lastAssistantThinking: string | null = null;
   202→  let lastAssistantLogEventId: number | null = null;
   203→  let lastThinkingLogEventId: number | null = null;
   204→  let lastThinkingUuid: string | null = null;
   205→  let lastToolsLogEventId: number | null = null;
   206→  let lastToolsUuid: string | null = null;
   207→  // All LogEvent IDs seen in the current assistant turn (thinking, text, tool_use may be separate events)
   208→  const currentTurnLogEventIds: number[] = [];
   209→
   210→  // TODO: look at which event types are useful.
   211→  const filtered = logEvents.filter(
   212→    (e) => !e.isSidechain && e.type !== "file-history-snapshot" && e.type !== "progress",
   213→  );
   214→
   215→  // Virtual SessionStart divider
   216→  const first = filtered[0];
   217→  if (first) {
   218→    result.push({ id: id--, timestamp: first.timestamp ?? "", event: "SessionStart", sessionId: first.sessionId ?? "", blocked: false, data: { cwd: first.cwd ?? "" }, summary: null, keywords: [], _sourceLogEventId: first.id });
   219→  }
   220→
   221→  for (const le of filtered) {
   222→    const ts  = le.timestamp ?? "";
   223→    const sid = le.sessionId ?? "";
   224→
   225→    if (le.type === "user") {
   226→      const toolResults = le.contents.filter((c) => c.contentType === "tool_result");
   227→      // TODO: show images and other content types
   228→      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
   229→
   230→      if (toolResults.length > 0) {
   231→        for (const tr of toolResults) {
   232→          const failed = tr.isError === true;
   233→          result.push({
   234→            id: id--,
   235→            timestamp: ts,
   236→            event: failed ? "PostToolUseFailure" : "PostToolUse",
   237→            sessionId: sid,
   238→            blocked: false,
   239→            data: {
   240→              tool_use_id:   tr.toolUseId,
   241→              tool_response: !failed ? (tr.toolResultContent ?? "") : undefined,
   242→              error:          failed ? (tr.toolResultContent ?? "") : undefined,
   243→            },
   244→            summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   245→          });
   246→        }
   247→      } else if (textBlocks.length > 0) {
   248→        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
   249→        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
   250→      }
   251→
   252→    } else if (le.type === "assistant") {
   253→      const toolUses      = le.contents.filter((c) => c.contentType === "tool_use");
   254→      const textBlocks    = le.contents.filter((c) => c.contentType === "text");
   255→      const thinkingBlocks = le.contents.filter((c) => c.contentType === "thinking");
   256→
   257→      // Track all LogEvent IDs in this turn so thinking-only events are reachable
   258→      if (!currentTurnLogEventIds.includes(le.id)) currentTurnLogEventIds.push(le.id);
   259→
   260→      if (textBlocks.length > 0) {
   261→        lastAssistantText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
   262→        lastAssistantLogEventId = le.id;
   263→      }
   264→      if (thinkingBlocks.length > 0) {
   265→        const thinking = thinkingBlocks.map((b) => b.thinking ?? "").filter(Boolean).join("\n\n");
   266→        lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + thinking : thinking;
   267→        lastThinkingLogEventId = le.id;
   268→        lastThinkingUuid = le.uuid ?? null;
   269→        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
   270→      }
   271→
   272→      for (const tu of toolUses) {
   273→        lastToolsLogEventId = le.id;
   274→        lastToolsUuid = le.uuid ?? null;
   275→        result.push({
   276→          id: id--,
   277→          timestamp: ts,
   278→          event: "PreToolUse",
   279→          sessionId: sid,
   280→          blocked: false,
   281→          data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput },
   282→          summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   283→        });
   284→      }
   285→
   286→    } else if (le.type === "system" && le.systemData?.subtype === "stop_hook_summary") {
   287→      const primaryId = lastAssistantLogEventId ?? le.id;
   288→      const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   289→      result.push({
   290→        id: id--,
   291→        timestamp: ts,
   292→        event: "Stop",
   293→        sessionId: sid,
   294→        blocked: le.systemData.preventedContinuation ?? false,
   295→        data: {
   296→          last_assistant_message: lastAssistantText ?? "",
   297→          thinking: lastAssistantThinking ?? "",
   298→          reason: le.systemData.stopReason ?? "",
   299→          thinkingLogEventId: lastThinkingLogEventId ?? undefined,
   300→          thinkingUuid: lastThinkingUuid ?? undefined,
   301→          toolsLogEventId: lastToolsLogEventId ?? undefined,
   302→          toolsUuid: lastToolsUuid ?? undefined,
   303→        },
   304→        summary: null, keywords: [],
   305→        _sourceLogEventId: primaryId,
   306→        _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   307→      });
   308→      lastAssistantText = null;
   309→      lastAssistantThinking = null;
   310→      lastAssistantLogEventId = null;
   311→      lastThinkingLogEventId = null;
   312→      lastThinkingUuid = null;
   313→      lastToolsLogEventId = null;
   314→      lastToolsUuid = null;
   315→      currentTurnLogEventIds.length = 0;
   316→    }
   317→  }
   318→
   319→  // Flush any trailing assistant text that had no stop event
   320→  if (lastAssistantText !== null && filtered.length > 0) {
   321→    const last = filtered[filtered.length - 1];
   322→    const primaryId = lastAssistantLogEventId ?? last.id;
   323→    const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   324→    result.push({
   325→      id: id--,
   326→      timestamp: last.timestamp ?? "",
   327→      event: "Stop",
   328→      sessionId: last.sessionId ?? "",
   329→      blocked: false,
   330→      data: { last_assistant_message: lastAssistantText, thinking: lastAssistantThinking ?? "", reason: "" },
   331→      summary: null, keywords: [],
   332→      _sourceLogEventId: primaryId,
   333→      _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   334→    });
   335→  }
   336→
   337→  return result;
   338→}
