   185→ * Reads:
   186→ *   <checkpointDir>/metadata.json             → CheckpointMetadata
   187→ *   <checkpointDir>/<n>/metadata.json         → CheckpointSessionMetadata
   188→ *   <checkpointDir>/<n>/content_hash.txt      → SessionLink.contentHash (actual hash)
   189→ *   <checkpointDir>/<n>/{full.jsonl,context.md,prompt.txt} → SessionLink paths
   190→ */
   191→export async function indexCheckpointV2(
   192→  db: PrismaClient,
   193→  checkpointDir: string,
   194→  checkpointId: string,
   195→  repoPath?: string,
   196→  mappedCheckpointIds?: Set<string>,
   197→): Promise<void> {
   198→  const metaPath = join(checkpointDir, "metadata.json");
   199→  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);
   200→
   201→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   202→
   203→  // Upsert CheckpointMetadata — create TokenUsage only on first insert
   204→  let checkpointMeta = await db.checkpointMetadata.findUnique({
   205→    where: { checkpointId },
   206→    select: { id: true },
   207→  });
   208→
   209→  if (!checkpointMeta) {
   210→    let tokenUsageId: number | null = null;
   211→    if (meta.token_usage) tokenUsageId = await createTokenUsage(db, meta.token_usage);
   212→    checkpointMeta = await db.checkpointMetadata.create({
   213→      data: {
   214→        checkpointId,
   215→        cliVersion:       meta.cli_version       ?? null,
   216→        branch:           meta.branch            ?? null,
   217→        strategy:         meta.strategy          ?? null,
   218→        checkpointsCount: meta.checkpoints_count ?? 0,
   219→        tokenUsageId,
   220→      },
   221→      select: { id: true },
   222→    });
   223→  } else {
   224→    await db.checkpointMetadata.update({
   225→      where: { checkpointId },
   226→      data: {
   227→        cliVersion:       meta.cli_version       ?? null,
   228→        branch:           meta.branch            ?? null,
   229→        strategy:         meta.strategy          ?? null,
   230→        checkpointsCount: meta.checkpoints_count ?? 0,
   231→      },
   232→    });
   233→  }
   234→
   235→  // files_touched → FilePath + join table
   236→  for (const filePath of meta.files_touched ?? []) {
   237→    const filePathId = await upsertFilePath(db, filePath);
   238→    await db.checkpointMetadataFilePath.upsert({
   239→      where: { checkpointMetadataId_filePathId: { checkpointMetadataId: checkpointMeta.id, filePathId } },
   240→      create: { checkpointMetadataId: checkpointMeta.id, filePathId },
   241→      update: {},
   242→    });
   243→  }
   244→
   245→  // Session sub-directories: 0/, 1/, …
   246→  const sessionDirs = readdirSync(checkpointDir)
   247→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   248→    .sort((a, b) => parseInt(a) - parseInt(b));
   249→
   250→  for (const sessionDir of sessionDirs) {
   251→    const sessionPath    = join(checkpointDir, sessionDir);
   252→    const metadataFile   = join(sessionPath, "metadata.json");
   253→    const transcriptFile = join(sessionPath, "full.jsonl");
   254→    const contextFile    = join(sessionPath, "context.md");
   255→    const hashFile       = join(sessionPath, "content_hash.txt");
   256→    const promptFile     = join(sessionPath, "prompt.txt");
   257→
   258→    // Read actual hash content (not the file path)
   259→    const contentHash = existsSync(hashFile) ? readFileSync(hashFile, "utf8").trim() : null;
   260→
   261→    // Look up an existing SessionLink for this transcript path.
   262→    const transcriptVal = existsSync(transcriptFile) ? transcriptFile : null;
   263→    const existing = transcriptVal
   264→      ? await db.sessionLink.findFirst({
   265→          where: { checkpointMetadataId: checkpointMeta.id, transcript: transcriptVal },
   266→          select: { id: true, contentHash: true },
   267→        })
   268→      : null;
   269→
   270→    // If the content hash hasn't changed, this session is fully indexed — skip it.
   271→    if (existing && contentHash && existing.contentHash === contentHash) continue;
   272→
   273→    let sessionLink: { id: number };
   274→    if (existing) {
   275→      // Hash changed (JSONL grew) — update the stored hash and re-index.
   276→      sessionLink = await db.sessionLink.update({
   277→        where: { id: existing.id },
   278→        data: { contentHash },
   279→        select: { id: true },
   280→      });
   281→    } else {
   282→      sessionLink = await db.sessionLink.create({
   283→        data: {
   284→          checkpointMetadataId: checkpointMeta.id,
   285→          metadata:   existsSync(metadataFile)   ? metadataFile   : null,
   286→          transcript: transcriptVal,
   287→          context:    existsSync(contextFile)    ? contextFile    : null,
   288→          contentHash,
   289→          prompt:     existsSync(promptFile)     ? promptFile     : null,
   290→        },
   291→        select: { id: true },
   292→      });
   293→    }
   294→
   295→    if (transcriptVal) {
   296→      await indexFullJsonl(db, transcriptVal, sessionLink.id);
   297→    }
   298→
   299→    if (!existsSync(metadataFile)) continue;
   300→
   301→    const sessionMeta = JSON.parse(readFileSync(metadataFile, "utf8")) as SessionMeta;
   302→    const { session_id: sessionId } = sessionMeta;
   303→    if (!sessionId) continue;
   304→
   305→    // CheckpointSessionMetadata — create or update
   306→    let sessionRecord = await db.checkpointSessionMetadata.findUnique({
   307→      where: { checkpointId_sessionId: { checkpointId, sessionId } },
   308→      select: { id: true },
   309→    });
   310→
   311→    if (!sessionRecord) {
   312→      let sessionTokenUsageId: number | null = null;
   313→      if (sessionMeta.token_usage) {
   314→        sessionTokenUsageId = await createTokenUsage(db, sessionMeta.token_usage);
   315→      }
   316→      sessionRecord = await db.checkpointSessionMetadata.create({
   317→        data: {
   318→          checkpointId,
   319→          sessionId,
   320→          cliVersion:       sessionMeta.cli_version       ?? null,
   321→          strategy:         sessionMeta.strategy          ?? null,
   322→          createdAt:        sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   323→          branch:           sessionMeta.branch            ?? null,
   324→          checkpointsCount: sessionMeta.checkpoints_count ?? 0,
   325→          agent:            sessionMeta.agent             ?? null,
   326→          turnId:           sessionMeta.turn_id           ?? null,
   327→          tokenUsageId:     sessionTokenUsageId,
   328→        },
   329→        select: { id: true },
   330→      });
   331→    } else {
   332→      await db.checkpointSessionMetadata.update({
   333→        where: { checkpointId_sessionId: { checkpointId, sessionId } },
   334→        data: {
   335→          cliVersion: sessionMeta.cli_version ?? null,
   336→          strategy:   sessionMeta.strategy    ?? null,
   337→          createdAt:  sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   338→          branch:     sessionMeta.branch      ?? null,
   339→          agent:      sessionMeta.agent       ?? null,
   340→          turnId:     sessionMeta.turn_id     ?? null,
   341→        },
   342→      });
   343→    }
   344→
   345→    // files_touched for session
   346→    for (const filePath of sessionMeta.files_touched ?? []) {
   347→      const filePathId = await upsertFilePath(db, filePath);
   348→      await db.checkpointSessionMetadataFilePath.upsert({
   349→        where: {
   350→          checkpointSessionMetadataId_filePathId: {
   351→            checkpointSessionMetadataId: sessionRecord.id,
   352→            filePathId,
   353→          },
   354→        },
   355→        create: { checkpointSessionMetadataId: sessionRecord.id, filePathId },
   356→        update: {},
   357→      });
   358→    }
   359→
   360→    // initial_attribution
   361→    if (sessionMeta.initial_attribution) {
   362→      const ia = sessionMeta.initial_attribution as Record<string, unknown>;
   363→      const iaData = {
   364→        calculatedAt:    ia.calculated_at ? new Date(ia.calculated_at as string) : null,
   365→        agentLines:      Number(ia.agent_lines      ?? 0),
   366→        humanAdded:      Number(ia.human_added      ?? 0),
   367→        humanModified:   Number(ia.human_modified   ?? 0),
   368→        humanRemoved:    Number(ia.human_removed    ?? 0),
   369→        totalCommitted:  Number(ia.total_committed  ?? 0),
   370→        agentPercentage: Number(ia.agent_percentage ?? 0),
   371→      };
   372→      await db.initialAttribution.upsert({
   373→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   374→        create: { checkpointSessionMetadataId: sessionRecord.id, ...iaData },
   375→        update: iaData,
   376→      });
   377→    }
   378→
   379→    // summary
   380→    if (sessionMeta.summary) {
   381→      const sm = sessionMeta.summary;
   382→      const summaryRecord = await db.checkpointSessionSummary.upsert({
   383→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   384→        create: { checkpointSessionMetadataId: sessionRecord.id, intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   385→        update: { intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   386→        select: { id: true },
   387→      });
   388→
   389→      // Recreate child arrays on every index pass (preserve status/subSessionId on OpenItem)
   390→      await Promise.all([
   391→        db.frictionItem.deleteMany( { where: { checkpointSessionSummaryId: summaryRecord.id } }),
   392→        db.repoLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   393→        db.codeLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   394→        db.workflowItem.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   395→      ]);
   396→
   397→      const creates: Promise<unknown>[] = [];
   398→
   399→      if (sm.open_items?.length) {
   400→        // Look up prior statuses for this session so they survive new checkpoints being indexed.
   401→        // Fetch ALL non-open prior items (not just exact matches) so we can fuzzy-match rephrased items.
   402→        const priorItems = await db.openItem.findMany({
   403→          where: {
   404→            checkpointSessionSummary: {
   405→              checkpointSessionMetadata: { sessionId },
   406→            },
   407→            status: { notIn: ["open"] },
   408→          },
   409→          select: { text: true, status: true, subSessionId: true },
   410→          distinct: ["text"],
   411→          orderBy: { id: "desc" },
   412→        });
   413→
   414→        // Build a map for exact matches and a list for fuzzy fallback
   415→        const priorByText = new Map(priorItems.map((p) => [p.text, p]));
   416→
   417→        // Jaccard similarity on word tokens (case-insensitive, punctuation-stripped)
   418→        function tokenize(s: string): Set<string> {
   419→          return new Set(s.toLowerCase().replace(/[^\w\s]/g, " ").split(/\s+/).filter(Boolean));
   420→        }
   421→        function jaccardSimilarity(a: string, b: string): number {
   422→          const ta = tokenize(a);
   423→          const tb = tokenize(b);
   424→          let intersection = 0;
   425→          for (const w of ta) if (tb.has(w)) intersection++;
   426→          const union = ta.size + tb.size - intersection;
   427→          return union === 0 ? 0 : intersection / union;
   428→        }
   429→
   430→        function findBestPrior(text: string) {
   431→          // Exact match first
   432→          if (priorByText.has(text)) return priorByText.get(text);
   433→          // Fuzzy fallback: best Jaccard match above 0.5 threshold
   434→          let best: { text: string; status: string; subSessionId: string | null } | undefined;
   435→          let bestScore = 0.5; // minimum threshold
   436→          for (const prior of priorItems) {
   437→            const score = jaccardSimilarity(text, prior.text);
   438→            if (score > bestScore) { bestScore = score; best = prior; }
   439→          }
   440→          return best;
   441→        }
   442→
   443→        creates.push(...sm.open_items.map((text) => {
   444→          const prior = findBestPrior(text);
   445→          return db.openItem.upsert({
   446→            where: { checkpointSessionSummaryId_text: { checkpointSessionSummaryId: summaryRecord.id, text } },
   447→            create: {
   448→              checkpointSessionSummaryId: summaryRecord.id,
   449→              text,
   450→              status: prior?.status ?? "open",
   451→              subSessionId: prior?.subSessionId ?? null,
   452→            },
   453→            update: {},
   454→          });
   455→        }));
   456→        // Remove open items that no longer appear in the source
   457→        creates.push(
   458→          db.openItem.deleteMany({
   459→            where: { checkpointSessionSummaryId: summaryRecord.id, text: { notIn: sm.open_items } },
   460→          })
   461→        );
   462→      } else {
   463→        creates.push(db.openItem.deleteMany({ where: { checkpointSessionSummaryId: summaryRecord.id } }));
   464→      }
   465→      if (sm.friction?.length) {
   466→        creates.push(db.frictionItem.createMany({
   467→          data: sm.friction.map((text) => ({ checkpointSessionSummaryId: summaryRecord.id, text })),
   468→        }));
   469→      }
   470→      if (sm.learnings?.repo?.length) {
   471→        creates.push(db.repoLearning.createMany({
   472→          data: sm.learnings.repo.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   473→        }));
   474→      }
   475→      if (sm.learnings?.code?.length) {
   476→        creates.push(db.codeLearning.createMany({
   477→          data: sm.learnings.code.map(({ path, finding }) => ({
   478→            checkpointSessionMetadataId: summaryRecord.id,
   479→            path,
   480→            finding,
   481→          })),
   482→        }));
   483→      }
   484→      if (sm.learnings?.workflow?.length) {
   485→        creates.push(db.workflowItem.createMany({
   486→          data: sm.learnings.workflow.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   487→        }));
   488→      }
   489→
   490→      await Promise.all(creates);
   491→    }
   492→  }
   493→
   494→  if (repoPath && !mappedCheckpointIds?.has(checkpointId)) {
   495→    await saveGitOidMapping(db, checkpointId, meta.branch, repoPath);
   496→  }
   497→}
   498→
   499→// ─── Full JSONL log indexer ───────────────────────────────────────────────────
   500→
   501→/**
   502→ * Parse a full.jsonl transcript file and write normalized rows to the LogEvent
   503→ * family of tables.  Already-indexed events (matched by uuid or messageId) are
   504→ * skipped so this function is safe to call multiple times on the same file.
   505→ *
   506→ * @param sessionLinkId  Optional FK into SessionLink so events can be traced
   507→ *                       back to the checkpoint/session that produced them.
   508→ */
   509→export async function indexFullJsonl(
   510→  db: PrismaClient,
   511→  transcriptPath: string,
   512→  sessionLinkId?: number,
   513→  shadowSessionId?: number,
   514→): Promise<{ events: number }> {
   515→  const content = readFileSync(transcriptPath, "utf8");
   516→  return indexFullJsonlContent(db, content, sessionLinkId, shadowSessionId);
   517→}
   518→
   519→export async function indexFullJsonlContent(
   520→  db: PrismaClient,
   521→  content: string,
   522→  sessionLinkId?: number,
   523→  shadowSessionId?: number,
   524→): Promise<{ events: number }> {
   525→  const events = parseFullJsonl(content);
   526→
   527→  // Pre-load known uuids / messageIds to skip duplicates without per-row queries.
   528→  const [existingUuids, existingMessageIds] = await Promise.all([
   529→    db.logEvent.findMany({ where: { uuid: { not: null } }, select: { uuid: true } })
   530→      .then((rows) => new Set(rows.map((r) => r.uuid as string))),
   531→    db.logEvent.findMany({ where: { messageId: { not: null } }, select: { messageId: true } })
   532→      .then((rows) => new Set(rows.map((r) => r.messageId as string))),
   533→  ]);
   534→
   535→  let count = 0;
   536→
   537→  for (const event of events) {
   538→    // Deduplication: skip if this event was already indexed.
   539→    if (event.uuid && existingUuids.has(event.uuid)) continue;
   540→    if (event.messageId && existingMessageIds.has(event.messageId)) continue;
   541→
   542→    const msg = event.message as Record<string, unknown> | undefined;
   543→
   544→    const logEvent = await db.logEvent.create({
   545→      data: {
   546→        uuid:            event.uuid            ?? null,
   547→        messageId:       event.messageId       ?? null,
   548→        sessionId:       event.sessionId       ?? null,
   549→        parentUuid:      event.parentUuid      ?? null,
   550→        type:            event.type,
   551→        timestamp:       event.timestamp ? new Date(event.timestamp) : null,
   552→        cwd:             event.cwd             ?? null,
   553→        gitBranch:       event.gitBranch       ?? null,
   554→        version:         event.version         ?? null,
   555→        slug:            event.slug            ?? null,
   556→        isSidechain:     event.isSidechain     ?? null,
   557→        userType:        event.userType        ?? null,
   558→        toolUseId:       event.toolUseID       ?? null,
   559→        parentToolUseId: event.parentToolUseID ?? null,
   560→        requestId:       (event.requestId as string | undefined) ?? null,
   561→        data:            JSON.stringify(event),
   562→        sessionLinkId:   sessionLinkId         ?? null,
   563→        shadowSessionId: shadowSessionId       ?? null,
   564→      },
   565→      select: { id: true },
   566→    });
   567→
   568→    // ── user / assistant: parse message content blocks ──────────────────────
   569→    if ((event.type === "user" || event.type === "assistant") && msg) {
   570→      const role = (msg.role as string | undefined) ?? event.type;
   571→      const rawContent = msg.content;
   572→      const contentArray: Record<string, unknown>[] =
   573→        Array.isArray(rawContent)
   574→          ? (rawContent as Record<string, unknown>[])
   575→          : typeof rawContent === "string"
   576→          ? [{ type: "text", text: rawContent }]
   577→          : [];
   578→
   579→      for (let i = 0; i < contentArray.length; i++) {
   580→        const c = contentArray[i];
   581→        const cType = (c.type as string | undefined) ?? "text";
   582→
   583→        // Stringify tool_result content if it's not already a string.
   584→        let toolResultContent: string | null = null;
   585→        if (cType === "tool_result") {
   586→          toolResultContent =
   587→            typeof c.content === "string"
   588→              ? c.content
   589→              : c.content != null
   590→              ? JSON.stringify(c.content)
   591→              : null;
   592→        }
   593→
   594→        await db.logContent.create({
   595→          data: {
   596→            logEventId:        logEvent.id,
   597→            role,
   598→            contentIndex:      i,
   599→            contentType:       cType,
   600→            text:              (c.text as string | undefined)         ?? null,
   601→            thinking:          (c.thinking as string | undefined)     ?? null,
   602→            toolUseId:         (c.id as string | undefined)           // tool_use block
   603→                            ?? (c.tool_use_id as string | undefined)  // tool_result block
   604→                            ?? null,
   605→            toolName:          (c.name as string | undefined)         ?? null,
   606→            toolInput:         c.input != null ? JSON.stringify(c.input) : null,
   607→            toolResultContent,
   608→            isError:           (c.is_error as boolean | undefined)    ?? null,
   609→          },
   610→        });
   611→      }
   612→
   613→      // ── assistant: token usage ────────────────────────────────────────────
   614→      if (event.type === "assistant") {
   615→        const u = msg.usage as Record<string, unknown> | undefined;
   616→        if (u) {
   617→          await db.logUsage.create({
   618→            data: {
   619→              logEventId:               logEvent.id,
   620→              model:                    (msg.model as string | undefined)       ?? null,
   621→              stopReason:               (msg.stop_reason as string | undefined) ?? null,
   622→              inputTokens:              Number(u.input_tokens               ?? 0),
   623→              cacheCreationInputTokens: Number(u.cache_creation_input_tokens ?? 0),
   624→              cacheReadInputTokens:     Number(u.cache_read_input_tokens     ?? 0),
   625→              outputTokens:             Number(u.output_tokens               ?? 0),
   626→            },
   627→          });
   628→        }
   629→      }
   630→    }
   631→
   632→    // ── progress: hook_progress data ─────────────────────────────────────────
   633→    if (event.type === "progress") {
   634→      const d = event.data as Record<string, unknown> | undefined;
   635→      await db.logHookProgress.create({
   636→        data: {
   637→          logEventId: logEvent.id,
   638→          type:       (d?.type      as string | undefined) ?? null,
   639→          hookEvent:  (d?.hookEvent as string | undefined) ?? null,
   640→          hookName:   (d?.hookName  as string | undefined) ?? null,
   641→          command:    (d?.command   as string | undefined) ?? null,
   642→        },
   643→      });
   644→    }
   645→
   646→    // ── system events ─────────────────────────────────────────────────────────
   647→    if (event.type === "system") {
   648→      const e = event as Record<string, unknown>;
   649→      await db.logSystemEvent.create({
   650→        data: {
   651→          logEventId:            logEvent.id,
   652→          subtype:               (e.subtype               as string  | undefined) ?? null,
   653→          hookCount:             (e.hookCount              as number  | undefined) ?? null,
   654→          stopReason:            (e.stopReason             as string  | undefined) ?? null,
   655→          preventedContinuation: (e.preventedContinuation  as boolean | undefined) ?? null,
   656→          level:                 (e.level                 as string  | undefined) ?? null,
   657→          durationMs:            (e.durationMs             as number  | undefined) ?? null,
   658→        },
   659→      });
   660→    }
   661→
   662→    // Mark as seen so a duplicate later in the same file is also skipped.
   663→    if (event.uuid)      existingUuids.add(event.uuid);
   664→    if (event.messageId) existingMessageIds.add(event.messageId);
   665→
   666→    count++;
   667→  }
   668→
   669→  return { events: count };
   670→}
   671→
   672→// ─── V2 full-tree indexer ─────────────────────────────────────────────────────
   673→
   674→export async function indexAllCheckpointsV2(
   675→  db: PrismaClient,
   676→  rootDir: string,
   677→  onProgress?: (checkpointId: string) => void,
   678→  repoPath?: string,
   679→): Promise<{ checkpoints: number }> {
   680→  let totalCheckpoints = 0;
   681→
   682→  // Pre-fetch all checkpoint IDs that already have a git OID mapping so we
   683→  // can skip the per-checkpoint DB read inside saveGitOidMapping.
   684→  let mappedCheckpointIds: Set<string> | undefined;
   685→  if (repoPath) {
   686→    const rows = await db.checkpointIdGitOidJoin.findMany({ select: { checkpointId: true } });
   687→    mappedCheckpointIds = new Set(rows.map((r) => r.checkpointId));
   688→  }
   689→
   690→  const shards = readdirSync(rootDir)
   691→    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
   692→
   693→  for (const shard of shards) {
   694→    const shardPath = join(rootDir, shard);
   695→    const ids = readdirSync(shardPath)
   696→      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
   697→
   698→    for (const rest of ids) {
   699→      const checkpointId  = shard + rest;
   700→      const checkpointDir = join(shardPath, rest);
   701→      try {
   702→        await indexCheckpointV2(db, checkpointDir, checkpointId, repoPath, mappedCheckpointIds);
   703→        mappedCheckpointIds?.add(checkpointId); // keep set current for this pass
   704→        totalCheckpoints++;
   705→        onProgress?.(checkpointId);
   706→      } catch (err) {
   707→        process.stderr.write(`indexer-v2: skipping ${checkpointId}: ${err}\n`);
   708→      }
   709→    }
   710→  }
   711→
   712→  // Sync FTS index with any new LogContent rows added during this pass
   713→  await setupLogContentFts(db);
   714→  await syncLogContentFts(db);
   715→
   716→  return { checkpoints: totalCheckpoints };
   717→}
   718→
   719→// ─── Full-tree indexer ───────────────────────────────────────────────────────
   720→
   721→/**
   722→ * Walk a checkpoints root directory and index every checkpoint found.
   723→ *
   724→ * The root must have the shard structure:
   725→ *   <root>/<2-hex-chars>/<10-hex-chars>/
   726→ *
   727→ * @param onProgress  Optional callback called after each checkpoint.
   728→ */
   729→export async function indexAllCheckpoints(
   730→  db: PrismaClient,
   731→  rootDir: string,
   732→  onProgress?: (checkpointId: string) => void,
   733→  repoPath?: string,
   734→): Promise<{ checkpoints: number }> {
   735→  const result = await indexAllCheckpointsV2(db, rootDir, onProgress, repoPath);
   736→  return { checkpoints: result.checkpoints };
   737→}
   738→
   739→// ─── Shadow branch indexer ────────────────────────────────────────────────────
   740→//
   741→// Shadow branches (entire/<commit>-<hash>) hold in-progress sessions that
   742→// haven't been committed to entire/checkpoints/v1 yet. Each branch contains:
   743→//
   744→//   .entire/metadata/<session-id>/full.jsonl   — live transcript
   745→//   .entire/metadata/<session-id>/prompt.txt   — initial user prompt
   746→//
   747→// We read these directly from git (git ls-tree + git cat-file blob) so we
   748→// don't need a worktree checkout. Change detection is via the git blob SHA.
   749→
   750→function gitExec(args: string, cwd: string): string {
   751→  return execSync(`git ${args}`, {
   752→    cwd,
   753→    encoding: "utf8",
   754→    stdio: ["ignore", "pipe", "ignore"],
   755→    maxBuffer: 64 * 1024 * 1024,
   756→  });
   757→}
   758→
   759→function getShadowBranches(repoPath: string): string[] {
   760→  try {
   761→    return gitExec("branch", repoPath)
   762→      .split("\n")
   763→      .map((l) => l.trim().replace(/^\* /, ""))
   764→      .filter((b) => b.startsWith("entire/") && !b.startsWith("entire/checkpoints"));
   765→  } catch { return []; }
   766→}
   767→
   768→function getShadowSessions(repoPath: string, branch: string): { sessionId: string; blobSha: string }[] {
   769→  try {
   770→    const output = gitExec(`ls-tree -r ${branch} -- .entire/metadata/`, repoPath);
   771→    const sessions = new Map<string, string>();
   772→    for (const line of output.split("\n")) {
   773→      const m = line.match(/^100644 blob ([0-9a-f]+)\s+\.entire\/metadata\/([^/]+)\/full\.jsonl$/);
   774→      if (m) sessions.set(m[2], m[1]);
   775→    }
   776→    return [...sessions.entries()].map(([sessionId, blobSha]) => ({ sessionId, blobSha }));
   777→  } catch { return []; }
   778→}
   779→
   780→function readBlobContent(repoPath: string, blobSha: string): string {
   781→  return gitExec(`cat-file blob ${blobSha}`, repoPath);
   782→}
   783→
   784→function readPromptFromBranch(repoPath: string, branch: string, sessionId: string): string | null {
   785→  try {
   786→    return gitExec(`show ${branch}:.entire/metadata/${sessionId}/prompt.txt`, repoPath).trim();
   787→  } catch { return null; }
   788→}
   789→
   790→/**
   791→ * Index all sessions from all local shadow branches (entire/<x>-<y>).
   792→ * Reads transcripts directly from git — no worktree required.
   793→ * Returns the number of sessions that had new or updated content.
   794→ */
   795→export async function indexAllShadowBranches(
   796→  db: PrismaClient,
   797→  repoPath: string,
   798→): Promise<{ sessions: number }> {
   799→  const branches = getShadowBranches(repoPath);
   800→  let totalSessions = 0;
   801→
   802→  for (const branch of branches) {
   803→    const sessions = getShadowSessions(repoPath, branch);
   804→
   805→    for (const { sessionId, blobSha } of sessions) {
   806→      // Skip if this exact blob SHA has already been indexed for this session.
   807→      // (Same session appears in multiple shadow branches as its transcript grows;
   808→      //  each branch may have a different SHA even for the same underlying content.)
   809→      const existing = await db.shadowSession.findUnique({ where: { sessionId } });
   810→      const seenShas: string[] = existing ? (JSON.parse(existing.seenBlobShas) as string[]) : [];
   811→      if (seenShas.includes(blobSha)) continue;
   812→
   813→      const fullJsonlContent = readBlobContent(repoPath, blobSha);
   814→      const events = parseFullJsonl(fullJsonlContent);
   815→
   816→      // Extract session metadata from the first event that carries it.
   817→      const firstMeta = events.find((e) => e.sessionId || e.cwd || e.gitBranch);
   818→      const cwd       = firstMeta?.cwd       ?? null;
   819→      const gitBranch = firstMeta?.gitBranch ?? null;
   820→      const createdAt = firstMeta?.timestamp ? new Date(firstMeta.timestamp) : null;
   821→      const prompt    = readPromptFromBranch(repoPath, branch, sessionId);
   822→      const newSeenShas = JSON.stringify([...seenShas, blobSha]);
   823→
   824→      const shadowSession = await db.shadowSession.upsert({
   825→        where:  { sessionId },
   826→        create: { sessionId, branch, seenBlobShas: newSeenShas, prompt, cwd, gitBranch, createdAt },
   827→        update: { branch, seenBlobShas: newSeenShas, prompt, cwd, gitBranch, createdAt },
   828→      });
   829→
   830→      const { events: newEvents } = await indexFullJsonlContent(db, fullJsonlContent, undefined, shadowSession.id);
   831→
   832→      process.stderr.write(`shadow indexer: indexed session ${sessionId.slice(0, 8)} (+${newEvents} events) from ${branch}\n`);
   833→      totalSessions++;
   834→    }
   835→  }
   836→
   837→  if (totalSessions > 0) {
   838→    await setupLogContentFts(db);
   839→    await syncLogContentFts(db);
   840→  }
   841→
   842→  return { sessions: totalSessions };
   843→}
